import AppKit

/// The Mac Clean **menu-bar widget** icon: the user-supplied vacuum
/// (Downloads/vacuum.png), cropped to its content and rendered white on
/// the brand purple-gradient squircle (fills ~82% of the tile so it
/// reads at 18px). Embedded as base64 (128px) so it loads identically
/// under `swift run` and inside the DMG.
///
/// ONLY the menu-bar widget icon. The main app icon
/// (Resources/AppIcon.icns) is intentionally left untouched.
enum VacuumAsset {
    // NSImage isn't Sendable; this is built once and only read, so it's
    // safe to mark unchecked for Swift 6 strict concurrency.
    nonisolated(unsafe) static let image: NSImage = {
        let b64 = ""
        guard let data = Data(base64Encoded: b64), let img = NSImage(data: data) else {
            return NSImage(systemSymbolName: "wand.and.sparkles", accessibilityDescription: "Mac Clean") ?? NSImage()
        }
        return img
    }()
}
